const input = items[0].json;

// Extrai telefone do key do WhatsApp, quando existir
function extractWhatsappPhoneFromKey(obj) {
  const key =
    obj?.body?.data?.key ??
    obj?.data?.key ??
    obj?.key ??
    {};

  const values = Object.values(key).filter(v => typeof v === 'string');

  const real = values.find(v => v.endsWith('@s.whatsapp.net'));
  if (real) return real.split('@')[0];

  const alt = values.find(v => {
    if (/@(lid|g\.us)$/.test(v)) return false;
    return /\d{8,}/.test(v);
  });

  if (alt) return alt.split('@')[0];

  return null;
}

// Normaliza telefone brasileiro
function normalizePhoneBR(value) {
  if (value === null || value === undefined) return null;

  let phone = String(value)
    .trim()
    .replace(/\D/g, '')
    .replace(/^0+/, '');

  if (!phone) return null;

  // Se já começa com 55, mantém
  if (!phone.startsWith('55')) {
    phone = `55${phone}`;
  }

  // Sempre retorna com +
  return `+${phone}`;
}

// Header fixo
const output = {
  lead_id: input.leadgen_id,
  created_time: input.created_time,
  page_id: input.page_id,
  form_id: input.form_id,
  campaign_name: input.campaign_name,
  adset_name: input.adset_name,
  ad_name: input.ad_name,
  ad_id: input.ad_id || "Outros",
  group_whats: input.groupID_whats || "",
  account_id: 3,
};

// Mapa explícito: nome original → nome curto
const map = {
  "hospedagem": "hospedagem",
  "hotel_para_quando": "hotel_para_quando",
  "idade_do_cao": "idade_do_cao",
  "idade_do_cão": "idade_do_cão",
  "sexo": "sexo_e_castracao",
  "sexo_do_cão": "sexo_e_castracao",
  "porte": "porte",
  "porte_do_cão": "porte",
  "raca": "raca",
  "raça": "raca",
  "nome_completo": "nome",
  "nome": "nome",
  "telefone": "telefone",
};

// Converte field_data com mapeamento controlado
for (const f of input.field_data || []) {
  const key = map[f.name];

  if (key) {
    const rawValue = f.values?.[0] ?? null;

    output[key] = rawValue !== null
      ? String(rawValue).replaceAll("_", " ")
      : null;
  }
}

// Prioridade:
// 1. telefone vindo do formulário
// 2. telefone vindo do key do WhatsApp
const telefoneFormulario = output.telefone;
const telefoneWhatsapp = extractWhatsappPhoneFromKey(input);

output.telefone = normalizePhoneBR(telefoneFormulario || telefoneWhatsapp);

return [{ json: output }];

