  funcionarios: "funcionarios",
  nicho: "nicho",
  investe: "investe",
  faturamento: "faturamento",
  site_instagram: "site_instagram",
  empresa: "empresa",
  nome_da_empresa: "empresa",
  company_name: "empresa",
  nome: "nome",
  first_name: "nome",
  whatsapp: "whatsapp",
  telefone: "whatsapp",
  phone_number: "whatsapp",
};

// Converte field_data com mapeamento controlado
for (const f of input.field_data || []) {
  const key = map[f.name];

  if (!key) continue;

  const valor = f.values?.[0];

  if (key === "whatsapp") {
    output[key] = normalizarWhatsapp(valor);
  } else {
    output[key] =
      valor != null
        ? String(valor).replaceAll("_", " ")
        : null;
  }
}

return [{ json: output }];

