function normalizarWhatsapp(valor) {
  if (!valor) return null;

  let numero = String(valor).replace(/\D/g, "");

  // Remove prefixo internacional 00, por exemplo: 005511982365652
  if (numero.startsWith("00")) {
    numero = numero.slice(2);
  }

  // Remove zero de operadora antes do DDD, por exemplo: 011982365652
  if (
    numero.startsWith("0") &&
    (numero.length === 11 || numero.length === 12)
  ) {
    numero = numero.slice(1);
  }

  // Número nacional: DDD + telefone, com 10 ou 11 dígitos
  if (numero.length === 10 || numero.length === 11) {
    numero = `55${numero}`;
  }

  // Caso não tenha DDI 55, adiciona
  else if (!numero.startsWith("55")) {
    numero = `55${numero}`;
  }

  return numero;
}

